def parse_record(record):

    ns = {"marc":"http://www.loc.gov/MARC21/slim"}
    xml = etree.fromstring(unicodedata.normalize("NFC", str(record)))

    #idn
    idn = xml.xpath("marc:controlfield[@tag = '001']", namespaces=ns)
    try:
        idn = idn[0].text
    except:
        idn = 'fail'

    # link
    link = xml.xpath("marc:datafield[@tag = '856']/marc:subfield[@code = 'u']", namespaces=ns)

    try:
        link = link[0].text
        #titel = unicodedata.normalize("NFC", titel)
    except:
        link = "unkown"

          # titel
    titel = xml.xpath("marc:datafield[@tag = '245']/marc:subfield[@code = 'a']", namespaces=ns)

    try:
        titel = titel[0].text
        #titel = unicodedata.normalize("NFC", titel)
    except:
        titel = "unkown"


    meta_dict = {"idn":idn,
                 "titel":titel,
                 "link":link}

    return meta_dict

Step 2 — Idempotency check helper
Before creating an item, search existing items by DNB IDN to avoid duplicates.

import requests as req

def find_item_by_idn(idn):
    """Return QID of an existing item with this DNB IDN, or None."""
    sparql = f"""
        SELECT ?item WHERE {{
          ?item wdt:{P_DNB_IDN} "{idn}" .
        }} LIMIT 1
    """
    try:
        resp = req.get(
            wbi_config["SPARQL_ENDPOINT_URL"],
            params={"query": sparql, "format": "json"},
            timeout=15,
        )
        bindings = resp.json()["results"]["bindings"]
        if bindings:
            return bindings[0]["item"]["value"].split("/")[-1]
    except Exception:
        pass
    return None

2. Abfrage verschiedener Datensätze der DNB
Die DNB bietet Ihre Daten über drei verschiedene “Kataloge” an, die entsprechend für eine Abfrage ausgewählt werden müssen. Dies geschieht über eine Erweiterung der o.g. Basis-URL. Zur Verfügung stehen folgende Kataloge: * Katalog der Deutschen Nationalbibliothek (DNB) - hierin befinden sich die Titeldaten* Katalog des Deutschen Musikarchivs (DMA) - Datensätze des Deutschen Musikarchivs* Katalog der Gemeinsamen Normdatei (GND) - hierin befinden sich die NormdatenDie Erweiterungen für die URL sind folgende: * DNB: https://services.dnb.de/sru/dnb* DMA: https://services.dnb.de/sru/dnb.dma* GND: https://services.dnb.de/sru/authoritiesWerden die jeweiligen Bereiche ohne weitere Spezifikationen abgefragt, senden sie eine Selbstbeschreibung im XML-Standardformat https://services.dnb.de/sru/dnb?operation=explain&version=1.1 zurück.

